}

.rev-tab-pill {
  border: 0;
  border-radius: 7px;
  padding: 7px 20px;
  font-size: var(--fs-base);
  font-weight: 500;
  color: var(--c-text-secondary);
  background: transparent;
  cursor: pointer;
  white-space: nowrap;
  transition: all 0.18s ease;
}

.rev-tab-pill:hover {
  color: var(--c-blue-600);
}

.rev-tab-pill.active {
  background: var(--c-blue-600);
  color: #fff;
  font-weight: 600;
  box-shadow: 0 2px 6px rgba(37,99,235,.35);
}

/* ============================================================
